import { task, logger, tasks } from "@trigger.dev/sdk";

const trial_id = "complex_agent_orchestration__BC8ArX5";

// Define the queue name
const queueName = `agent-queue-${trial_id}`;

/**
 * Simulates a search.
 * Accepts a query and returns a result.
 */
export const searchTask = task({
  id: `searchTask-${trial_id}`,
  run: async (payload: { query: string }) => {
    logger.info(`Searching for: ${payload.query}`);

    // Simulate search logic
    if (payload.query.includes("complex")) {
      return { result: "insufficient information found for complex query" };
    }

    return { result: `Search result for ${payload.query}` };
  },
});

/**
 * Research agent that executes sub-tasks, evaluates results, and recurses if necessary.
 */
export const researchAgent = task({
  id: `researchAgent-${trial_id}`,
  queue: {
    name: queueName,
    concurrencyLimit: 2,
  },
  run: async (payload: { query: string; depth?: number }): Promise<string> => {
    const depth = payload.depth ?? 1;
    logger.info(`Researching: ${payload.query} at depth ${depth}`);

    // 1. If depth > 2, return "Max depth reached".
    if (depth > 2) {
      return "Max depth reached";
    }

    // 2. Trigger a sub-task searchTask using triggerAndWait to simulate a search.
    const searchResult = await searchTask.triggerAndWait({
      query: payload.query,
    });

    if (!searchResult.ok) {
      throw new Error(`Search task failed: ${String(searchResult.error)}`);
    }

    const { result } = searchResult.output;

    // 3. If the search result contains "insufficient", recursively trigger researchAgent
    // with depth + 1 and a refined query.
    if (result.includes("insufficient")) {
      const refinedQuery = `${payload.query} refined`;
      logger.info(`Insufficient info. Recursing with query: ${refinedQuery}`);

      // Use tasks.triggerAndWait to avoid circular reference issues in some TS versions
      const recursiveResult = await tasks.triggerAndWait<typeof researchAgent>(`researchAgent-${trial_id}`, {
        query: refinedQuery,
        depth: depth + 1,
      });

      if (!recursiveResult.ok) {
         throw new Error(`Recursive research agent failed: ${String(recursiveResult.error)}`);
      }

      return recursiveResult.output;
    }

    // 4. Otherwise, return the final result.
    return result;
  },
});

